- [ ] **Step 1.7.2: Implement**

`lib/api/mutation-helpers.ts`:

```ts
import { showSuccessToast, showErrorToast } from '@/lib/toast-utils';
import { ApiError, ApiErrorCodes } from './errors';

interface WithToastOpts {
  success?: string;
}

export function withToast(opts: WithToastOpts) {
  return {
    onSuccess: () => {
      if (opts.success) showSuccessToast(opts.success);
    },
    onError: (error: unknown) => {
      if (error instanceof ApiError && error.code === ApiErrorCodes.AUTH_EXPIRED) {
        return;
      }
      const message = error instanceof Error ? error.message : 'Có lỗi xảy ra';
      showErrorToast(message);
    },
  };
}
```

