  limit?: number;
  is_signed?: boolean;
}

export function payrollKey(filters: PayrollFilters) {
  return ['payroll', filters] as const;
}

export function usePayrollSearchQuery(filters: PayrollFilters, enabled = true) {
  return useQuery({
    queryKey: payrollKey(filters),
    queryFn: ({ signal }) => {
      const params = new URLSearchParams();
      Object.entries(filters).forEach(([k, v]) => {
        if (v !== undefined && v !== '' && v !== null) params.set(k, String(v));
      });
      return apiClient.get<PayrollListResponse>(
        `/api/admin/payroll?${params.toString()}`,
        { signal },
