    },
    enabled,
    staleTime: 30_000,
    placeholderData: (prev) => prev,
  });
}

export function usePayrollDetailQuery(employeeId: string, salaryMonth: string) {
  return useQuery({
    queryKey: ['payroll-detail', employeeId, salaryMonth],
    queryFn: ({ signal }) =>
      apiClient.get<PayrollDetail>(
        `/api/admin/payroll/${employeeId}/${salaryMonth}`,
        { signal },
      ),
    enabled: Boolean(employeeId && salaryMonth),
