```tsx
'use client';

import { useRef, type ReactNode } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import {
  Table,
  TableBody,
  TableHeader,
  TableRow,
  TableHead,
  TableCell,
} from '@/components/ui/table';

export interface VirtualColumn<T> {
  key: string;
  header: ReactNode;
  cell: (row: T, index: number) => ReactNode;
  width?: string | number;
}

interface VirtualizedTableProps<T> {
  data: T[];
  columns: VirtualColumn<T>[];
  estimateRowHeight?: number;
  overscan?: number;
  enabledThreshold?: number;
  containerHeight?: number | string;
  rowKey: (row: T, index: number) => string;
  emptyState?: ReactNode;
}

export function VirtualizedTable<T>({
  data,
  columns,
  estimateRowHeight = 56,
  overscan = 5,
  enabledThreshold = 100,
  containerHeight = 600,
  rowKey,
  emptyState,
}: VirtualizedTableProps<T>) {
  const parentRef = useRef<HTMLDivElement>(null);
  const shouldVirtualize = data.length >= enabledThreshold;

  const virtualizer = useVirtualizer({
    count: data.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => estimateRowHeight,
    overscan,
  });

  if (data.length === 0 && emptyState) {
    return <div className="p-4 text-center text-muted-foreground">{emptyState}</div>;
  }

  if (!shouldVirtualize) {
    return (
      <Table>
        <TableHeader>
          <TableRow>
            {columns.map((c) => (
              <TableHead key={c.key} style={{ width: c.width }}>
                {c.header}
              </TableHead>
            ))}
          </TableRow>
        </TableHeader>
        <TableBody>
          {data.map((row, idx) => (
            <TableRow key={rowKey(row, idx)}>
              {columns.map((c) => (
                <TableCell key={c.key}>{c.cell(row, idx)}</TableCell>
              ))}
            </TableRow>
          ))}
        </TableBody>
      </Table>
    );
  }

  return (
    <div
      ref={parentRef}
      style={{
        height: typeof containerHeight === 'number' ? `${containerHeight}px` : containerHeight,
        overflow: 'auto',
      }}
      className="border rounded"
    >
      <div style={{ height: `${virtualizer.getTotalSize()}px`, position: 'relative' }}>
        <Table>
          <TableHeader className="sticky top-0 bg-background z-10">
            <TableRow>
              {columns.map((c) => (
                <TableHead key={c.key} style={{ width: c.width }}>
                  {c.header}
                </TableHead>
              ))}
            </TableRow>
          </TableHeader>
          <TableBody>
            {virtualizer.getVirtualItems().map((virtualRow) => {
              const row = data[virtualRow.index];
              return (
                <TableRow
                  key={rowKey(row, virtualRow.index)}
                  data-index={virtualRow.index}
                  ref={(el) => virtualizer.measureElement(el)}
                  style={{
                    position: 'absolute',
                    top: 0,
                    left: 0,
                    width: '100%',
                    transform: `translateY(${virtualRow.start}px)`,
                  }}
                >
                  {columns.map((c) => (
                    <TableCell key={c.key}>{c.cell(row, virtualRow.index)}</TableCell>
                  ))}
                </TableRow>
              );
            })}
          </TableBody>
        </Table>
      </div>
    </div>
  );
}
```

