import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { apiClient } from '@/lib/api/client';
import { withToast } from '@/lib/api/mutation-helpers';

export interface PayrollFilters {
  month?: string;
  payroll_type?: 'monthly' | 't13';
  employee_id?: string;
  department?: string;
  page?: number;
  limit?: number;
  is_signed?: boolean;
}

export function payrollKey(filters: PayrollFilters) {
  return ['payroll', filters] as const;
}

export function usePayrollSearchQuery(filters: PayrollFilters, enabled = true) {
  return useQuery({
    queryKey: payrollKey(filters),
    queryFn: ({ signal }) => {
      const params = new URLSearchParams();
      Object.entries(filters).forEach(([k, v]) => {
        if (v !== undefined && v !== '' && v !== null) params.set(k, String(v));
      });
      return apiClient.get<PayrollListResponse>(
        `/api/admin/payroll?${params.toString()}`,
        { signal },
      );
    },
    enabled,
    staleTime: 30_000,
    placeholderData: (prev) => prev,
  });
}

export function usePayrollDetailQuery(employeeId: string, salaryMonth: string) {
  return useQuery({
    queryKey: ['payroll-detail', employeeId, salaryMonth],
    queryFn: ({ signal }) =>
      apiClient.get<PayrollDetail>(
        `/api/admin/payroll/${employeeId}/${salaryMonth}`,
        { signal },
      ),
    enabled: Boolean(employeeId && salaryMonth),
    staleTime: 0, // sensitive data
  });
}

export function useSignSalaryMutation() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (input: { employee_id: string; salary_month: string }) =>
      apiClient.post('/api/employee/sign-salary', input),
    ...withToast({ success: 'Đã ký lương' }),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['payroll'] });
      qc.invalidateQueries({ queryKey: ['dashboard-stats'] });
      qc.invalidateQueries({ queryKey: ['signature-progress'] });
    },
  });
}

