      payrollQuery,
      supabase
        .from("signature_logs")
        .select("employee_id, signed_by_name, signed_at")
        .eq("salary_month", salary_month),
      supabase
        .from("management_signatures")
        .select("*")
        .eq("salary_month", salary_month)
        .eq("is_active", true),
    ]);

